namespace Axions.Core.Features.Airports.Queries.GetAirports;

/// <summary>
/// GetsAirportsQuery
/// </summary>
public class GetAirportsQuery: PaginationRequest, IRequest<BaseResultDto<PaginatedResult<AirportDto>>>
{
    /// <summary>
    /// Gets or sets Keyword.
    /// </summary>
    public string? Keyword { get; set; }

    /// <summary>
    /// Gets or sets IsActive.
    /// </summary>
    public bool? IsActive { get; set; }

    public Expression<Func<Airport, bool>> Predicate()
    {
        var predicate = PredicateBuilder.True<Airport>();

        if (!Keyword.IsNullOrEmpty())
        {
            var keywordPredicate = PredicateBuilder.False<Airport>();
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Name) && x.Name!.ToLower().Contains(Keyword!.ToLower()));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.IataCode) && x.IataCode!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.Country) && x.Country!.Contains(Keyword!));
            keywordPredicate = keywordPredicate.Or(x => !string.IsNullOrEmpty(x.City) && x.City!.Contains(Keyword!));

            predicate = predicate.And(keywordPredicate);
        }

        if (IsActive.HasValue)
            predicate = predicate.And(x => x.IsActive == IsActive);

        return predicate;
    }
}

/// <summary>
/// Handler for GetAirportsQuery.
/// </summary>
public class GetAirportQueryHandler(ApplicationDbContext context, IMapper mapper) : IRequestHandler<GetAirportsQuery, BaseResultDto<PaginatedResult<AirportDto>>>
{
    public async Task<BaseResultDto<PaginatedResult<AirportDto>>> Handle(GetAirportsQuery request, CancellationToken cancellationToken)
    {
        var entities = await context.Airports
            .Where(request.Predicate())
            .AsNoTracking()
            .ProjectToPaginatedList<Airport, AirportDto>(mapper, request, cancellationToken)
            .ConfigureAwait(false);

        return entities.ResultDto<PaginatedResult<AirportDto>>();
    }
}

